<template>
  <div>
    <h3 class="page-title">标签管理</h3>
    <el-table :data="tags" stripe v-loading="loading">
      <el-table-column prop="id" label="ID" width="60" />
      <el-table-column prop="name" label="名称" />
      <el-table-column prop="category" label="分类">
        <template slot-scope="{row}"><el-tag size="mini">{{ row.category }}</el-tag></template>
      </el-table-column>
      <el-table-column label="色标">
        <template slot-scope="{row}"><span class="color-dot" :style="{background: row.color}"></span></template>
      </el-table-column>
    </el-table>
  </div>
</template>

<script>
import { tagApi } from '../../api';
export default {
  name: 'AdminTags',
  data() { return { tags: [], loading: true }; },
  created() { this.load(); },
  methods: {
    async load() {
      this.loading = true;
      const res = await tagApi.getAll();
      if (res.code === 200) this.tags = res.data || [];
      this.loading = false;
    }
  }
};
</script>

<style scoped>
.color-dot { display: inline-block; width: 20px; height: 20px; border-radius: 50%; vertical-align: middle; }
</style>
